"""
Script de patch para atualizar generate_period_csvs() em opponents_report.py.
Substitui o metodo inteiro de forma precisa, independente de line endings.
"""
import re

file_path = "opponents_report.py"

with open(file_path, "r", encoding="utf-8-sig") as f:
    content = f.read()

OLD_METHOD_START = "    def generate_period_csvs(self, player_tag: str):\r\n"
OLD_METHOD_END = "        return arquivos_gerados\r\n"

# Encontra onde o metodo comeca e termina
start_idx = content.find(OLD_METHOD_START)
if start_idx == -1:
    # Tenta com \n
    OLD_METHOD_START = OLD_METHOD_START.replace("\r\n", "\n")
    OLD_METHOD_END = OLD_METHOD_END.replace("\r\n", "\n")
    start_idx = content.find(OLD_METHOD_START)

if start_idx == -1:
    print("ERRO: Nao encontrei o inicio do metodo generate_period_csvs")
    exit(1)

# Encontra o fim: localiza a proxima funcao/metodo depois do metodo atual
# O fim e marcado pelo "return arquivos_gerados" seguido de nova funcao (4 espacos def)
end_search_from = start_idx + len(OLD_METHOD_START)
end_idx = content.find(OLD_METHOD_END, end_search_from)
if end_idx == -1:
    print("ERRO: Nao encontrei o final do metodo")
    exit(1)
end_idx += len(OLD_METHOD_END)

print(f"Metodo encontrado: caracteres {start_idx} a {end_idx}")
print(f"Primeiros 100 chars: {repr(content[start_idx:start_idx+100])}")

# Detecta o tipo de newline usado no arquivo
nl = "\r\n" if "\r\n" in content else "\n"

NEW_METHOD = f'''    def generate_period_csvs(self, player_tag: str):{nl}        """Gera CSVs para dia, semana, mes e ano atual (acumulados do banco){nl}        {nl}        PROTECAO: O arquivo diario de um dia anterior nao sera sobrescrito.{nl}        DETECCAO DE LACUNAS: Emite alertas quando houver intervalo suspeito entre batalhas.{nl}        Retorna: tuple(arquivos_gerados, alertas_gap){nl}        """{nl}        now_utc = datetime.utcnow(){nl}        brt_offset = timedelta(hours=-3){nl}        now_brt = now_utc + brt_offset{nl}        {nl}        # Periodo: Dia atual{nl}        dia_inicio_brt = now_brt.replace(hour=0, minute=0, second=0, microsecond=0){nl}        dia_fim_brt = now_brt.replace(hour=23, minute=59, second=59, microsecond=999999){nl}        dia_inicio = dia_inicio_brt - brt_offset{nl}        dia_fim = dia_fim_brt - brt_offset{nl}        {nl}        # Periodo: Semana atual (segunda a domingo){nl}        dias_semana = now_brt.weekday()  # 0 = segunda, 6 = domingo{nl}        semana_inicio_brt = (now_brt - timedelta(days=dias_semana)).replace(hour=0, minute=0, second=0, microsecond=0){nl}        semana_inicio = semana_inicio_brt - brt_offset{nl}        semana_fim = dia_fim{nl}        {nl}        # Periodo: Mes atual{nl}        mes_inicio_brt = now_brt.replace(day=1, hour=0, minute=0, second=0, microsecond=0){nl}        mes_inicio = mes_inicio_brt - brt_offset{nl}        mes_fim = dia_fim{nl}        {nl}        # Periodo: Ano atual{nl}        ano_inicio_brt = now_brt.replace(month=1, day=1, hour=0, minute=0, second=0, microsecond=0){nl}        ano_inicio = ano_inicio_brt - brt_offset{nl}        ano_fim = dia_fim{nl}        {nl}        # Pasta de saida oficial{nl}        output_dir = self.csv_manager.data_dir{nl}        # Configura factory para acessar colunas por nome{nl}        conn = sqlite3.connect(self.db_path, uri=True){nl}        conn.row_factory = sqlite3.Row{nl}        cursor = conn.cursor(){nl}        {nl}        # Funcao auxiliar para formatar data para query SQL (formato ISO: YYYY-MM-DD){nl}        def format_date_for_query(dt):{nl}            return dt.strftime('%Y-%m-%d %H:%M:%S'){nl}        {nl}        # Busca batalhas por periodo{nl}        periodos = {{{nl}            'dia': {{{nl}                'inicio': format_date_for_query(dia_inicio),{nl}                'fim': format_date_for_query(dia_fim),{nl}                'arquivo': os.path.join(output_dir, f"oponentes_dia_{{now_brt.strftime('%Y%m%d')}}.csv"),{nl}                'proteger_passado': True  # Nao sobrescrever arquivos de dias anteriores{nl}            }},{nl}            'semana': {{{nl}                'inicio': format_date_for_query(semana_inicio),{nl}                'fim': format_date_for_query(dia_fim),{nl}                'arquivo': os.path.join(output_dir, f"oponentes_semana_{{now_brt.year}}{{now_brt.strftime('%V')}}.csv"),{nl}                'proteger_passado': False{nl}            }},{nl}            'mes': {{{nl}                'inicio': format_date_for_query(mes_inicio),{nl}                'fim': format_date_for_query(dia_fim),{nl}                'arquivo': os.path.join(output_dir, f"oponentes_mes_{{now_brt.year}}{{now_brt.strftime('%m')}}.csv"),{nl}                'proteger_passado': False{nl}            }},{nl}            'ano': {{{nl}                'inicio': format_date_for_query(ano_inicio),{nl}                'fim': format_date_for_query(dia_fim),{nl}                'arquivo': os.path.join(output_dir, f"oponentes_ano_{{now_brt.year}}.csv"),{nl}                'proteger_passado': False{nl}            }}{nl}        }}{nl}        {nl}        arquivos_gerados = []{nl}        alertas_gap = []{nl}        {nl}        for periodo_nome, periodo_info in periodos.items():{nl}            output_file = periodo_info['arquivo']{nl}            {nl}            # PROTECAO: Nao sobrescrever arquivos de dias anteriores.{nl}            # O arquivo diario identifica o DIA no nome (ex: oponentes_dia_20260427.csv).{nl}            # Se ja existe E nao e o dia atual, esta finalizado — nao reescrever.{nl}            # Alteracao: 2026-04-29 - Protecao de arquivos de dias passados{nl}            if periodo_info.get('proteger_passado', False) and os.path.exists(output_file):{nl}                nome_arquivo = os.path.basename(output_file){nl}                data_arquivo = nome_arquivo.replace('oponentes_dia_', '').replace('.csv', ''){nl}                data_hoje = now_brt.strftime('%Y%m%d'){nl}                if data_arquivo != data_hoje:{nl}                    print(f"[PROTEGIDO] {{nome_arquivo}} pertence a um dia anterior — nao sera sobrescrito."){nl}                    continue{nl}            {nl}            # Query usando comparacao de strings (battle_time no formato ISO: YYYY-MM-DD HH:MM:SS){nl}            query = """{nl}                SELECT * FROM oponentes_batalhas {nl}                WHERE player_tag = ? {nl}                AND battle_time >= ? {nl}                AND battle_time <= ?{nl}                ORDER BY battle_time DESC{nl}            """{nl}            params = (player_tag, periodo_info['inicio'], periodo_info['fim']){nl}            {nl}            cursor.execute(query, params){nl}            rows = cursor.fetchall(){nl}            {nl}            if not rows:{nl}                print(f"Nenhuma batalha encontrada para o periodo {{periodo_nome}}."){ nl}                continue{nl}            {nl}            # Converte para dicionarios{nl}            opponents_data = []{nl}            battle_times_iso = []  # Para deteccao de lacunas{nl}            for row in rows:{nl}                # Fallback para data formatada se estiver vazia{nl}                data_fmt = row['data_formatada']{nl}                if not data_fmt or data_fmt == '':{nl}                    try:{nl}                        dt = datetime.strptime(row['battle_time'], '%Y-%m-%d %H:%M:%S'){nl}                        data_fmt = dt.strftime('%d/%m/%Y %H:%M'){nl}                    except:{nl}                        data_fmt = row['battle_time']{nl}{nl}                opponents_data.append({{{nl}                    'data': data_fmt,{nl}                    'nome_oponente': row['nome_oponente'],{nl}                    'tag_oponente': row['tag_oponente'],{nl}                    'nivel_oponente': row['nivel_oponente'],{nl}                    'trofes_oponente': row['trofes_oponente'],{nl}                    'clan_oponente': row['clan_oponente'],{nl}                    'resultado': row['resultado'],{nl}                    'coroas_jogador': row['coroas_jogador'],{nl}                    'coroas_oponente': row['coroas_oponente'],{nl}                    'mudanca_trofes': row['mudanca_trofes'],{nl}                    'modo_jogo': row['modo_jogo'],{nl}                    'tipo_batalha': row['tipo_batalha'],{nl}                    'arena': row['arena'],{nl}                    'deck_jogador': row['deck_jogador'],{nl}                    'deck_oponente': row['deck_oponente']{nl}                }}){nl}                {nl}                if row['battle_time']:{nl}                    battle_times_iso.append(row['battle_time']){nl}            {nl}            # DETECCAO DE LACUNAS: verifica intervalos suspeitos entre batalhas consecutivas.{nl}            # Limiar de 90 minutos: coleta a cada 30min deveria garantir sem perdas.{nl}            # Alteracao: 2026-04-29 - Adicionado detector de gaps para identificar falhas de coleta{nl}            if periodo_nome == 'dia' and len(battle_times_iso) >= 2:{nl}                GAP_LIMIAR_MINUTOS = 90{nl}                times_sorted = sorted(battle_times_iso){nl}                for i in range(1, len(times_sorted)):{nl}                    try:{nl}                        t_anterior = datetime.strptime(times_sorted[i-1], '%Y-%m-%d %H:%M:%S'){nl}                        t_atual = datetime.strptime(times_sorted[i], '%Y-%m-%d %H:%M:%S'){nl}                        diff_minutos = (t_atual - t_anterior).total_seconds() / 60{nl}                        if diff_minutos > GAP_LIMIAR_MINUTOS:{nl}                            alerta = ({nl}                                f"[ALERTA-GAP] Lacuna de {{int(diff_minutos)}} min detectada: "{nl}                                f"entre {{times_sorted[i-1]}} e {{times_sorted[i]}} (UTC). "{nl}                                f"Possivel perda de batalhas neste intervalo."{nl}                            ){nl}                            print(alerta){nl}                            alertas_gap.append(alerta){nl}                    except (ValueError, TypeError):{nl}                        continue{nl}            {nl}            # Conta repeticoes{nl}            opponent_tags = [op['tag_oponente'] for op in opponents_data if op['tag_oponente']]{nl}            opponent_counts = Counter(opponent_tags){nl}            {nl}            # Adiciona contador de repeticoes{nl}            for opponent_info in opponents_data:{nl}                tag = opponent_info['tag_oponente']{nl}                count = opponent_counts.get(tag, 0){nl}                opponent_info['vezes_enfrentado'] = count{nl}            {nl}            fieldnames = [{nl}                'data', 'nome_oponente', 'tag_oponente', 'nivel_oponente', {nl}                'trofes_oponente', 'clan_oponente', 'resultado', {nl}                'coroas_jogador', 'coroas_oponente', 'mudanca_trofes',{nl}                'modo_jogo', 'tipo_batalha', 'arena', 'deck_jogador', 'deck_oponente', 'vezes_enfrentado'{nl}            ]{nl}            {nl}            # Sempre reescreve o arquivo com dados atualizados do banco (acumulado){nl}            with open(output_file, 'w', newline='', encoding='utf-8-sig') as csvfile:{nl}                writer = csv.DictWriter(csvfile, fieldnames=fieldnames){nl}                writer.writeheader(){nl}                writer.writerows(opponents_data){nl}            {nl}            arquivos_gerados.append(output_file){nl}            print(f"CSV {{periodo_nome}} gerado: {{output_file}} ({{len(opponents_data)}} batalhas)"){nl}        {nl}        conn.close(){nl}        {nl}        # Retorna tuple com arquivos gerados e alertas de lacuna para uso no workflow{nl}        return arquivos_gerados, alertas_gap{nl}'''

new_content = content[:start_idx] + NEW_METHOD + content[end_idx:]

with open(file_path, "w", encoding="utf-8-sig") as f:
    f.write(new_content)

print("Patch aplicado com sucesso!")
print(f"Arquivo tinha {len(content)} chars, agora tem {len(new_content)} chars")

# Verifica se a funcao foi inserida corretamente
with open(file_path, "r", encoding="utf-8-sig") as f:
    check = f.read()
if "PROTECAO: Nao sobrescrever" in check and "ALERTA-GAP" in check:
    print("Verificacao OK: protecao e deteccao de gaps foram inseridas corretamente.")
else:
    print("AVISO: Verificacao falhou!")
